from typing import Any

def create_refund(
    order_id: str,
    amount_cents: int,
    reason: str,
    dry_run: bool = False,
) -> dict[str, Any]:
    """Issue a refund. Set dry_run=True to preview without committing."""
    # Validation runs regardless of dry_run
    if amount_cents <= 0:
        return {"error": "VALIDATION_ERROR",
                "message": "amount_cents must be positive"}
    if len(reason.strip()) < 5:
        return {"error": "VALIDATION_ERROR",
                "message": "reason must be at least 5 characters"}

    # Look up the order to validate it exists and is refundable
    order = _get_order(order_id)
    if order is None:
        return {"error": "NOT_FOUND", "message": f"Order {order_id} not found"}
    if order["status"] not in ("delivered", "shipped"):
        return {"error": "VALIDATION_ERROR",
                "message": f"Order in status '{order['status']}' cannot be refunded"}
    if amount_cents > order["total_cents"]:
        return {"error": "VALIDATION_ERROR",
                "message": f"Refund amount exceeds order total of {order['total_cents']} cents"}

    if dry_run:
        return {
            "dry_run": True,
            "would_refund": {
                "order_id": order_id,
                "amount_cents": amount_cents,
                "reason": reason,
                "customer_email": order["customer_email"],
                "estimated_processing_days": 3,
            },
            "message": "Dry run complete. Call again with dry_run=False to issue the refund.",
        }

    # Real execution
    result = _issue_refund(order_id, amount_cents, reason)
    return {
        "refund_id": result["id"],
        "amount_cents": amount_cents,
        "status": result["status"],
    }

import secrets
from datetime import datetime, timezone, timedelta
from typing import Any

# In-memory approval token store (use Redis or DB in production)
_APPROVALS: dict[str, dict] = {}   # token -> {tool, inputs, expires_at, used}

def request_approval(
    tool_name: str,
    inputs: dict[str, Any],
    session_id: str,
    ttl_seconds: int = 300,
) -> dict[str, Any]:
    """
    Generate an approval request the model can present to the user.
    The token is single-use and expires after ttl_seconds.
    """
    token = secrets.token_urlsafe(16)
    _APPROVALS[token] = {
        "tool": tool_name,
        "inputs": inputs,
        "session_id": session_id,
        "expires_at": datetime.now(timezone.utc) + timedelta(seconds=ttl_seconds),
        "used": False,
    }
    return {
        "status": "APPROVAL_REQUIRED",
        "approval_token": token,
        "expires_in_seconds": ttl_seconds,
        "message": (
            f"The action '{tool_name}' requires your explicit approval. "
            f"Reply with the token '{token}' to proceed, or 'cancel' to abort."
        ),
    }

def execute_with_approval(
    tool_name: str,
    inputs: dict[str, Any],
    approval_token: str,
    session_id: str,
    registry,
) -> dict[str, Any]:
    record = _APPROVALS.get(approval_token)
    if record is None:
        return {"error": "PERMISSION_DENIED", "message": "Invalid approval token"}
    if record["used"]:
        return {"error": "PERMISSION_DENIED", "message": "Approval token already used"}
    if datetime.now(timezone.utc) > record["expires_at"]:
        return {"error": "PERMISSION_DENIED", "message": "Approval token has expired"}
    if record["session_id"] != session_id:
        return {"error": "PERMISSION_DENIED", "message": "Token session mismatch"}
    if record["tool"] != tool_name or record["inputs"] != inputs:
        return {"error": "PERMISSION_DENIED",
                "message": "Approval token does not match this tool call"}

    record["used"] = True   # consume the token
    tool_def = registry.get(tool_name)
    if tool_def is None:
        return {"error": "NOT_FOUND", "message": f"Tool '{tool_name}' not found"}
    return tool_def.handler(**inputs)

_BULK_LIMITS: dict[str, int] = {
    "send_bulk_email":    500,   # max recipients per call
    "bulk_update_status": 100,   # max records per call
    "export_data":        1000,  # max rows per export
}

def send_bulk_email(
    recipient_ids: list[str],
    subject: str,
    body: str,
    dry_run: bool = False,
) -> dict[str, Any]:
    limit = _BULK_LIMITS["send_bulk_email"]
    if len(recipient_ids) > limit:
        return {
            "error": "VALIDATION_ERROR",
            "message": f"Cannot send to more than {limit} recipients in a single call. "
                       f"Received {len(recipient_ids)}. Split into batches.",
            "max_recipients": limit,
        }
    if dry_run:
        return {
            "dry_run": True,
            "would_send_to": len(recipient_ids),
            "subject": subject,
            "message": "Dry run. Call with dry_run=False to send.",
        }
    # ... real send
    return {"sent": len(recipient_ids), "status": "queued"}
